// User registration
function custom_user_registration($username, $password, $email) {
    $userdata = array(
        'user_login' => $username,
        'user_pass' => $password,
        'user_email' => $email,
    );

    $user_id = wp_insert_user($userdata);

    if (!is_wp_error($user_id)) {
        wp_set_password($password, $user_id);
    }
}

// User login authentication
function custom_user_login($username, $password) {
    $creds = array(
        'user_login' => $username,
        'user_password' => $password,
        'remember' => true,
    );

    $user = wp_signon($creds, false);

    if (is_wp_error($user)) {
        echo $user->get_error_message();
    }
}

// Password hashing
function custom_hash_password($password) {
    return password_hash($password, PASSWORD_BCRYPT);
}

// Verify hashed password
function custom_verify_password($password, $hashed_password) {
    return password_verify($password, $hashed_password);
}

// Hook into 'register_new_user' action
add_action('register_new_user', 'custom_user_registration', 10, 3);

// Hook into 'wp_authenticate' action
add_action('wp_authenticate', 'custom_user_login', 10, 2);
